@@ -559,10 +566,11 @@ func (h *AuthHandler) GitHubCallback(c *fiber.Ctx) error {
 	// OAuth exchange instead of leaking the goroutine until timeout.
 	ctx, cancel := context.WithTimeout(c.UserContext(), githubHTTPTimeout)
